type cand struct {
	idx      int
	score    float64
	feasible bool
}
const alpha = 0.7
const beta = 0.3
const gamma = 100.0
for shipIdx := range oris {
	var bestCand cand
	bestCand.score = 1e18
	var feasCands []cand
	for i := 0; i < dispatch.AssignsLen; i++ {
		cb := dispatch.Assigns[i].Cost
		ok := dispatch.Assigns[i].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
		if ok {
			dispatch.Assigns[i].GenRoute()
			if dispatch.Assigns[i].Cost >= 0 {
				mc := dispatch.Assigns[i].Cost - cb
				stationsCnt := len(dispatch.Assigns[i].Stations)
				utilScore := alpha*mc + beta*(cal_dis(oris[shipIdx], dess[shipIdx])/gamma) - float64(stationsCnt)*0.001
				feasCands = append(feasCands, cand{i, utilScore, true})
			}
		}
		dispatch.Assigns[i].RemoveShip(total_ship + shipIdx)
		dispatch.Assigns[i].GenRoute()
	}
	for _, fc := range feasCands {
		if fc.feasible && fc.score < bestCand.score {
			bestCand = fc
		}
	}
	inserted := false
	if bestCand.idx != -1 {
		ok := dispatch.Assigns[bestCand.idx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
		if ok {
			dispatch.Assigns[bestCand.idx].GenRoute()
			if dispatch.Assigns[bestCand.idx].Cost >= 0 {
				inserted = true
			} else {
				dispatch.Assigns[bestCand.idx].RemoveShip(total_ship + shipIdx)
				dispatch.Assigns[bestCand.idx].GenRoute()
			}
		}
	}
	if !inserted {
		if dispatch.AssignsLen < MAXASSIGNS {
			nxt := dispatch.AssignsLen
			ok := dispatch.Assigns[nxt].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if ok {
				dispatch.Assigns[nxt].GenRoute()
				if dispatch.Assigns[nxt].Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					dispatch.Assigns[nxt].RemoveShip(total_ship + shipIdx)
					dispatch.Assigns[nxt].GenRoute()
				}
			}
		}
	}
	if !inserted && dispatch.AssignsLen < MAXASSIGNS {
		startAt := dispatch.AssignsLen
		for j := startAt; j < MAXASSIGNS; j++ {
			ok := dispatch.Assigns[j].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if ok {
				dispatch.Assigns[j].GenRoute()
				if dispatch.Assigns[j].Cost >= 0 {
					dispatch.AssignsLen = j + 1
					inserted = true
					break
				}
				dispatch.Assigns[j].RemoveShip(total_ship + shipIdx)
				dispatch.Assigns[j].GenRoute()
			}
		}
		if !inserted && dispatch.AssignsLen == 0 && MAXASSIGNS > 0 {
			ok := dispatch.Assigns[0].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if ok {
				dispatch.Assigns[0].GenRoute()
				if dispatch.Assigns[0].Cost >= 0 {
					dispatch.AssignsLen = 1
					inserted = true
				} else {
					dispatch.Assigns[0].RemoveShip(total_ship + shipIdx)
					dispatch.Assigns[0].GenRoute()
				}
			}
		}
	}
}
dispatch.RenewnTotalCost()
